example.code:
import { createVar } from '@vanilla-extract/css';
import { recipe, RecipeVariants } from '@vanilla-extract/recipes';

const focusColor = createVar();

export const button = recipe({
  base: {
    display: 'inline-flex',
    fontWeight: 500,
    borderRadius: '0.375rem',
    cursor: 'pointer',
    vars: { [focusColor]: '#3b82f6' },
    ':focus-visible': { outline: `2px solid ${focusColor}`, outlineOffset: '2px' },
  },
  variants: {
    color: {
      primary: { background: '#3b82f6', color: '#fff', ':hover': { background: '#2563eb' } },
      secondary: { background: '#f3f4f6', color: '#1f2937' },
    },
    size: {
      sm: { padding: '0.375rem 0.75rem', fontSize: '0.875rem' },
      md: { padding: '0.5rem 1rem', fontSize: '1rem' },
    },
  },
  defaultVariants: { color: 'primary', size: 'md' },
});

export type ButtonVariants = RecipeVariants<typeof button>;

// ❌ BROKEN
import { isDarkMode } from '../utils/theme'; // imports window.matchMedia
export const styles = recipe({
  base: isDarkMode() ? { color: '#fff' } : { color: '#000' },
});

// ✅ CORRECT
import { tokens } from './tokens'; // literal object, no app code
export const styles = recipe({
  base: { color: tokens.color.primary },
});

// lib/registry.tsx
'use client';
import { createContext, useContext, useState, useRef } from 'react';
import { useServerInsertedHTML } from 'next/navigation';
import { ServerStyleSheet, StyleSheetManager } from 'styled-components';

export default function StyledComponentsRegistry({ children }: { children: React.ReactNode }) {
  const [styledSheet] = useState(() => new ServerStyleSheet());
  useServerInsertedHTML(() => {
    const styles = styledSheet.getStyleElement();
    styledSheet.instance.clearTag();
    return <>{styles}</>;
  });
  return <StyleSheetManager sheet={styledSheet.instance}>{children}</StyleSheetManager>;
}

// app/layout.tsx
import StyledComponentsRegistry from '@/lib/registry';

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html>
      <body>
        <StyledComponentsRegistry>{children}</StyledComponentsRegistry>
      </body>
    </html>
  );
}

test('styles are in initial HTML (no FOUC)', async ({ request }) => {
  const res = await request.get('/');
  const html = await res.text();
  expect(html).toMatch(/data-styled/);
});
